#include <iostream>
#include <string>
#include <algorithm>

int main() {
    int n, base;
    std::cin >> n >> base;
    std::string result = "";
    char digits[] = "0123456789ABCDEF";
    if (n == 0) {
        std::cout << "0" << std::endl;
        return 0;
    }
    while (n > 0) {
        result = digits[n % base] + result;
        n /= base;
    }
    std::cout << result << std::endl;
    return 0;
}
